fix:
public Date read(JsonReader in) throws IOException {
  if (in.peek() != JsonToken.NULL && in.peek() != JsonToken.STRING) {
      throw new JsonParseException("The date should be either NULL or a string value");
  }

  // Handling null values gracefully, as per JSR353 standard https://jcp.org/en/jsr/detail?id=353
  if (in.peek() == JsonToken.NULL) {
     in.nextNull();
     return null;
  }
  String stringValue = in.nextString();
  Date date = deserializeToDate(stringValue);
  if (dateType == Date.class) {
    return date;
  } else if (dateType == Timestamp.class) {
    return new Timestamp(date.getTime());
  } else if (dateType == java.sql.Date.class) {
    return new java.sql.Date(date.getTime());
  } else {
    // This must never happen: dateType is guarded in the primary constructor
    throw new AssertionError();
  }
}

